import json

# Tier-1 edges that require qualifier
TIER_1_EDGES = {
    'SIBLING_OF', 'SPOUSE_OF', 'PARENT_OF', 'WARD_OF', 
    'HOLDS_TITLE', 'VOWS_TO', 'MANIPULATES', 'SWORN_TO'
}

# Required fields per decision type
REQUIRED_FIELDS = {
    'emit_edge': ['decision', 'candidate_kind', 'evidence_kind', 'source_slug', 'target_slug', 'edge_type', 'evidence_snippet', 'evidence_section', 'confidence_tier'],
    'reject_just_mention': ['decision', 'candidate_kind', 'source_slug', 'target_slug', 'reason']
}

def validate_file(filepath, filename):
    """Validate JSONL file for schema compliance."""
    errors = []

    with open(filepath) as f:
        for line_num, line in enumerate(f, 1):
            try:
                row = json.loads(line)
            except json.JSONDecodeError as e:
                errors.append(f"Line {line_num}: Invalid JSON - {e}")
                continue

            decision = row.get('decision')

            # Check required fields for this decision type
            if decision in REQUIRED_FIELDS:
                required = REQUIRED_FIELDS[decision]
                for field in required:
                    if field not in row:
                        errors.append(f"Line {line_num}: {decision} missing required field '{field}'")

            # Check Tier-1 qualifier requirement
            if decision == 'emit_edge':
                edge_type = row.get('edge_type')
                if edge_type in TIER_1_EDGES:
                    if 'qualifier' not in row:
                        errors.append(f"Line {line_num}: Tier-1 edge {edge_type} missing 'qualifier' field")

                # Validate confidence_tier is an integer 1-3
                ct = row.get('confidence_tier')
                if not isinstance(ct, int) or ct not in [1, 2, 3]:
                    errors.append(f"Line {line_num}: confidence_tier must be int 1-3, got {ct}")

    if errors:
        print(f"\n{filename}: {len(errors)} validation errors")
        for err in errors[:5]:  # Show first 5
            print(f"  {err}")
        if len(errors) > 5:
            print(f"  ... and {len(errors)-5} more")
    else:
        print(f"\n{filename}: ✓ All rows valid")

base = '/Users/mnoth/source/asoiaf-chat/working/wiki/pass2-buckets/characters-house-frey-e-m/prose-edges-haiku'

for fname in ['malwyn-frey.edges.jsonl', 'marissa-frey.edges.jsonl', 'merianne-frey.edges.jsonl', 
              'martyn-rivers.edges.jsonl', 'merrett-frey.edges.jsonl']:
    validate_file(f'{base}/{fname}', fname)

EOFPYTHON
